-- 2026-05-04 -- EventInvite template seed
--
-- Resolved by /lib/events/sendEventInvite.ts via sendMessage({ templateSlug:
-- 'event-invite' }). Variables passed in:
--   {{test_prefix}}      -- empty string or "[TEST] " for test sends
--   {{first_name}}       -- contact.first_name
--   {{event_name}}       -- e.g. "Content Creation Day"
--   {{event_date}}       -- e.g. "Thursday, May 7"
--   {{event_time}}       -- e.g. "11 AM to 12 PM"
--   {{event_address}}    -- full address line
--   {{slots_remaining}}  -- digit string
--   {{slots_total}}      -- digit string
--   {{hero_image_url}}   -- public URL of flyer PNG in event-assets bucket
--   {{rsvp_instruction}} -- "Reply or text 480.204.2983 to lock your slot."
--
-- send_mode = 'resend' -- coming from alex@alexhollienco.com (Resend-verified
-- domain, not the Gmail account). Phase 0 confirmed DKIM at
-- resend._domainkey.alexhollienco.com and SPF on send.alexhollienco.com.
-- kind = 'transactional' -- explicit owner-triggered invite per recipient.
--
-- Voice: Sotheby's prestige + Flodesk warmth + Apple precision per brand.md.
-- No banned words (stunning/breathtaking/amazing). No exclamation marks
-- except the subject which earns one for the invite framing. No em dashes
-- (double-hyphen `--` per Standing Rule 2).
--
-- Idempotent via ON CONFLICT (slug, version) DO UPDATE. user_id passed
-- explicitly per slice5b/7C precedent (CLI push runs as service_role with
-- no JWT; auth.uid() default returns NULL).

INSERT INTO public.templates (user_id, slug, version, name, send_mode, kind, subject, body_html, body_text)
VALUES
  (
    'b735d691-4d86-4e31-9fd3-c2257822dca3'::uuid,
    'event-invite',
    1,
    'Event Invite -- Generic',
    'resend',
    'transactional',
    E'{{test_prefix}}{{first_name}}, you are invited to {{event_name}} on {{event_date}}',
    E'<!DOCTYPE html>\n<html lang="en"><head><meta charset="utf-8"><meta name="viewport" content="width=device-width,initial-scale=1"><title>{{event_name}}</title><link href="https://fonts.googleapis.com/css2?family=Instrument+Serif:ital@0;1&family=Inter:wght@300;400;500;600&display=swap" rel="stylesheet"></head>\n<body style="margin:0;padding:0;background:#f7f7f5;font-family:Inter,Helvetica,Arial,sans-serif;color:#0a0a0a;-webkit-font-smoothing:antialiased;">\n<table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f7f7f5;padding:24px 12px;"><tr><td align="center">\n<table role="presentation" width="600" cellpadding="0" cellspacing="0" style="max-width:600px;background:#ffffff;border-radius:6px;overflow:hidden;">\n  <tr><td style="padding:0;">\n    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#0a0a0a;color:#ffffff;">\n      <tr><td style="padding:36px 32px 28px 32px;">\n        <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:11px;letter-spacing:0.18em;text-transform:uppercase;color:#C6B79B;margin:0 0 14px 0;">You are invited</p>\n        <h1 style="font-family:\'Instrument Serif\',Georgia,serif;font-size:38px;line-height:1.1;color:#ffffff;margin:0 0 14px 0;font-weight:400;">{{event_name}}</h1>\n        <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:13px;letter-spacing:0.12em;text-transform:uppercase;color:#ffffff;margin:0;opacity:0.85;">{{event_date}}  &middot;  {{event_time}}</p>\n      </td></tr>\n    </table>\n  </td></tr>\n  <tr><td style="padding:32px 32px 8px 32px;">\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:16px;line-height:1.55;color:#0a0a0a;margin:0 0 18px 0;">Hi {{first_name}},</p>\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:16px;line-height:1.6;color:#0a0a0a;margin:0 0 18px 0;">Christine McConnell and I are co-hosting <strong>{{event_name}}</strong> on <strong>{{event_date}}</strong> from <strong>{{event_time}}</strong>, and I would love to have you there.</p>\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:16px;line-height:1.6;color:#0a0a0a;margin:0 0 24px 0;">Walk in with ideas. Walk out with professionally filmed short-form video content shot inside a luxury Scottsdale listing. Script prompts and on-set direction included.</p>\n  </td></tr>\n  <tr><td style="padding:0 32px 24px 32px;">\n    <table role="presentation" width="100%" cellpadding="0" cellspacing="0" style="background:#f7f7f5;border-left:3px solid #003087;">\n      <tr><td style="padding:18px 22px;">\n        <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:11px;letter-spacing:0.16em;text-transform:uppercase;color:#003087;margin:0 0 10px 0;font-weight:600;">Event Details</p>\n        <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:15px;line-height:1.65;color:#0a0a0a;margin:0;">\n          <strong>{{event_date}}</strong>, {{event_time}}<br>\n          {{event_address}}<br>\n          <strong>{{slots_remaining}} of {{slots_total}} slots remaining</strong>\n        </p>\n      </td></tr>\n    </table>\n  </td></tr>\n  <tr><td style="padding:0 32px 8px 32px;">\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:11px;letter-spacing:0.16em;text-transform:uppercase;color:#666666;margin:0 0 12px 0;font-weight:600;">What you walk away with</p>\n    <table role="presentation" width="100%" cellpadding="0" cellspacing="0">\n      <tr><td style="padding:6px 0;font-family:Inter,Helvetica,Arial,sans-serif;font-size:15px;line-height:1.55;color:#0a0a0a;"><span style="color:#b31a35;font-weight:600;">&bull;</span>&nbsp; Professionally filmed short-form video content</td></tr>\n      <tr><td style="padding:6px 0;font-family:Inter,Helvetica,Arial,sans-serif;font-size:15px;line-height:1.55;color:#0a0a0a;"><span style="color:#b31a35;font-weight:600;">&bull;</span>&nbsp; Script prompts and on-set direction</td></tr>\n      <tr><td style="padding:6px 0;font-family:Inter,Helvetica,Arial,sans-serif;font-size:15px;line-height:1.55;color:#0a0a0a;"><span style="color:#b31a35;font-weight:600;">&bull;</span>&nbsp; Luxury listing as your backdrop</td></tr>\n      <tr><td style="padding:6px 0 18px 0;font-family:Inter,Helvetica,Arial,sans-serif;font-size:15px;line-height:1.55;color:#0a0a0a;"><span style="color:#b31a35;font-weight:600;">&bull;</span>&nbsp; Designed for real estate and personal branding</td></tr>\n    </table>\n  </td></tr>\n  <tr><td style="padding:0 32px 12px 32px;">\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:11px;letter-spacing:0.16em;text-transform:uppercase;color:#666666;margin:0 0 14px 0;font-weight:600;">Brought to you by</p>\n    <table role="presentation" width="100%" cellpadding="0" cellspacing="0"><tr>\n      <td width="25%" style="padding:0 6px 0 0;vertical-align:top;font-family:Inter,Helvetica,Arial,sans-serif;font-size:13px;line-height:1.4;color:#0a0a0a;">\n        <strong style="display:block;color:#0a0a0a;">Christine McConnell</strong><span style="color:#666666;font-size:12px;">Nations Lending</span>\n      </td>\n      <td width="25%" style="padding:0 6px;vertical-align:top;font-family:Inter,Helvetica,Arial,sans-serif;font-size:13px;line-height:1.4;color:#0a0a0a;">\n        <strong style="display:block;color:#0a0a0a;">Alex Hollien</strong><span style="color:#666666;font-size:12px;">Great American Title</span>\n      </td>\n      <td width="25%" style="padding:0 6px;vertical-align:top;font-family:Inter,Helvetica,Arial,sans-serif;font-size:13px;line-height:1.4;color:#0a0a0a;">\n        <strong style="display:block;color:#0a0a0a;">Zachary Johnson</strong><span style="color:#666666;font-size:12px;">Goosehead Insurance</span>\n      </td>\n      <td width="25%" style="padding:0 0 0 6px;vertical-align:top;font-family:Inter,Helvetica,Arial,sans-serif;font-size:13px;line-height:1.4;color:#0a0a0a;">\n        <strong style="display:block;color:#0a0a0a;">Mark Keeten</strong><span style="color:#666666;font-size:12px;">Poindexter Moving</span>\n      </td>\n    </tr></table>\n  </td></tr>\n  <tr><td style="padding:24px 32px 8px 32px;">\n    <a href="{{hero_image_url}}" target="_blank" style="text-decoration:none;display:block;"><img src="{{hero_image_url}}" alt="{{event_name}} flyer" width="536" style="display:block;width:100%;max-width:536px;height:auto;border-radius:4px;border:1px solid #e8e8e8;"></a>\n  </td></tr>\n  <tr><td style="padding:24px 32px 8px 32px;">\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:16px;line-height:1.6;color:#0a0a0a;margin:0 0 14px 0;">{{rsvp_instruction}}</p>\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:16px;line-height:1.6;color:#0a0a0a;margin:0 0 28px 0;">Looking forward to it,<br><span style="font-family:\'Instrument Serif\',Georgia,serif;font-size:22px;font-style:italic;color:#0a0a0a;">Alex</span></p>\n  </td></tr>\n  <tr><td style="padding:18px 32px 32px 32px;border-top:1px solid #e8e8e8;">\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:12px;line-height:1.6;color:#666666;margin:0 0 8px 0;"><strong style="color:#0a0a0a;">Alex Hollien</strong>  &middot;  Title Sales Executive</p>\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:12px;line-height:1.6;color:#666666;margin:0 0 8px 0;font-style:italic;">I make sure the transaction you promised your client is the transaction they experience.</p>\n    <p style="font-family:Inter,Helvetica,Arial,sans-serif;font-size:11px;line-height:1.6;color:#999999;margin:0;">Title and Escrow Services Provided by Great American Title Agency</p>\n  </td></tr>\n</table>\n</td></tr></table>\n</body></html>',
    E'Hi {{first_name}},\n\nChristine McConnell and I are co-hosting {{event_name}} on {{event_date}} from {{event_time}}, and I would love to have you there.\n\nWalk in with ideas. Walk out with professionally filmed short-form video content shot inside a luxury Scottsdale listing. Script prompts and on-set direction included.\n\nEVENT DETAILS\n{{event_date}}, {{event_time}}\n{{event_address}}\n{{slots_remaining}} of {{slots_total}} slots remaining\n\nWhat you walk away with:\n  - Professionally filmed short-form video content\n  - Script prompts and on-set direction\n  - Luxury listing as your backdrop\n  - Designed for real estate and personal branding\n\nBrought to you by:\n  Christine McConnell, Nations Lending\n  Alex Hollien, Great American Title\n  Zachary Johnson, Goosehead Insurance\n  Mark Keeten, Poindexter Moving\n\nFlyer: {{hero_image_url}}\n\n{{rsvp_instruction}}\n\nLooking forward to it,\nAlex\n\n--\nAlex Hollien | Title Sales Executive\nI make sure the transaction you promised your client is the transaction they experience.\nTitle and Escrow Services Provided by Great American Title Agency'
  )
ON CONFLICT (slug, version) DO UPDATE
SET
  name       = EXCLUDED.name,
  send_mode  = EXCLUDED.send_mode,
  kind       = EXCLUDED.kind,
  subject    = EXCLUDED.subject,
  body_html  = EXCLUDED.body_html,
  body_text  = EXCLUDED.body_text,
  updated_at = now();
